func (w *Worker) Start() error {
	const op = "worker.(*Worker).Start"

	w.statusMutex.Lock()
	defer w.statusMutex.Unlock()

	if !atomic.CompareAndSwapInt32(&w.started, 0, 1) {
		return errors.New(w.baseContext, errors.AlreadyClosed, op, "worker already started")
	}
	w.started = true

	metric.SetWorkerId(w.WardenMetricsManager, w.conf.WorkerId)
	if w.wardenMetricsManager != nil {
		metric.StartWorkersReporting(w.wardenMetricsManager, w.conf.Eventer, w.baseContext)
	}

	ctx, cancel := context.WithCancel(w.baseContext)
	w.ctx = ctx

	if err := w.setupForShutdown(); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.startUpstreamController(ctx); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.setupListenerCallbacks(); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.startClusterConnections(ctx); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.loadLocalSessions(w.ctx); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.processWorkerSignal(ctx); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

	if err := w.startSessionManager(ctx); err != nil {
		cancel()
		return errors.Wrap(w.baseContext, err, op)
	}

